INSERT INTO `wp_fsmpt_email_logs` VALUES (22,NULL,'a:1:{i:0;a:1:{s:5:\"email\";s:26:\"gestorcontenidos@neema.com\";}}','NEEMA Toolkit <davidvt04@gmail.com>','Activa tu cuenta','<div style=\"max-width: 560px;padding: 20px;background: #3D3073;border-radius: 10px;margin: 40px auto;font-family: \'Open Sans\', Helvetica, Arial, sans-serif;font-size: 15px;color: #ffffff\">\r\n    <!-- Header -->\r\n    <div style=\"text-align: center;font-weight: bold;font-size: 28px;padding: 15px 0;border-bottom: 3px solid #5A45A0\">\r\n        NEEMA-Toolkit    </div>\r\n    \r\n    <!-- Body -->\r\n    <div style=\"padding: 30px;line-height: 1.6\">\r\n        <h2 style=\"font-size: 22px;font-weight: 600;text-align: center;margin-bottom: 25px\">\r\n            ¡Gracias por registrarte en NEEMA!        </h2>\r\n        <p style=\"text-align: center;font-size: 16px;margin-bottom: 30px\">\r\n            Para activar tu cuenta, por favor haz clic en el botón de abajo:        </p>\r\n        <div style=\"text-align: center;margin-bottom: 40px\">\r\n            <a style=\"background-color: #f6ebf8;color: #3d3073;padding: 12px 30px;text-decoration: none;border-radius: 5px;font-weight: 600\" href=\"http://neema-toolkit-tfg.local/sign-up-es/?act=activate_account&#038;user_id=7&#038;code=EBbYT3JwxAAN6kjfAXHl\">\r\n                Activar mi cuenta            </a>\r\n        </div>\r\n        <p style=\"text-align: center;font-size: 14px;color: #e0dff4\">\r\n            ¿Necesitas ayuda? \r\n            <a style=\"color: #ff9f1c;text-decoration: none\" href=\"mailto:neematoolkit@us.es\">\r\n                Contáctanos            </a>\r\n        </p>\r\n    </div>\r\n    \r\n    <!-- Footer -->\r\n    <div style=\"text-align: center;font-size: 13px;color: #d1cfe8;padding: 20px 30px\">\r\n        Gracias,<br />\r\n        El equipo de NEEMA <br />\r\n    </div>\r\n</div>\r\n','a:4:{s:8:\"reply-to\";a:0:{}s:2:\"cc\";a:0:{}s:3:\"bcc\";a:0:{}s:12:\"content-type\";s:9:\"text/html\";}','a:0:{}','sent','a:1:{s:9:\"MessageId\";s:16:\"19e321c28c3f2975\";}','a:1:{s:8:\"provider\";s:5:\"gmail\";}',0,0,NULL,'2026-05-16 18:46:06',NULL);
INSERT INTO `wp_fsmpt_email_logs` VALUES (23,NULL,'a:1:{i:0;a:1:{s:5:\"email\";s:24:\"adminfuncional@neema.com\";}}','NEEMA Toolkit <davidvt04@gmail.com>','Activate your account','<div style=\"max-width: 560px;padding: 20px;background: #3D3073;border-radius: 10px;margin: 40px auto;font-family: \'Open Sans\', Helvetica, Arial, sans-serif;font-size: 15px;color: #ffffff\">\r\n    <!-- Header -->\r\n    <div style=\"text-align: center;font-weight: bold;font-size: 28px;padding: 15px 0;border-bottom: 3px solid #5A45A0\">\r\n        NEEMA-Toolkit    </div>\r\n    \r\n    <!-- Body -->\r\n    <div style=\"padding: 30px;line-height: 1.6\">\r\n        <h2 style=\"font-size: 22px;font-weight: 600;text-align: center;margin-bottom: 25px\">\r\n            Thank you for signing up at NEEMA!        </h2>\r\n        <p style=\"text-align: center;font-size: 16px;margin-bottom: 30px\">\r\n            To activate your account, please click the button below:        </p>\r\n        <div style=\"text-align: center;margin-bottom: 40px\">\r\n            <a style=\"background-color: #f6ebf8;color: #3d3073;padding: 12px 30px;text-decoration: none;border-radius: 5px;font-weight: 600\" href=\"http://neema-toolkit-tfg.local/en/sign-up-en/?act=activate_account&#038;user_id=8&#038;code=JzGESpGEYdCgcr9RzwJe\">\r\n                Activate my account            </a>\r\n        </div>\r\n        <p style=\"text-align: center;font-size: 14px;color: #e0dff4\">\r\n            Need help? \r\n            <a style=\"color: #ff9f1c;text-decoration: none\" href=\"mailto:neematoolkit@us.es\">\r\n                Contact us            </a>\r\n        </p>\r\n    </div>\r\n    \r\n    <!-- Footer -->\r\n    <div style=\"text-align: center;font-size: 13px;color: #d1cfe8;padding: 20px 30px\">\r\n        Thank you,<br />\r\n        The NEEMA Team <br />\r\n    </div>\r\n</div>\r\n','a:4:{s:8:\"reply-to\";a:0:{}s:2:\"cc\";a:0:{}s:3:\"bcc\";a:0:{}s:12:\"content-type\";s:9:\"text/html\";}','a:0:{}','sent','a:1:{s:9:\"MessageId\";s:16:\"19e3220e54c632b8\";}','a:1:{s:8:\"provider\";s:5:\"gmail\";}',0,0,NULL,'2026-05-16 18:51:17',NULL);
INSERT INTO `wp_fsmpt_email_logs` VALUES (24,NULL,'a:1:{i:0;a:1:{s:5:\"email\";s:26:\"gestorcontenidos@neema.com\";}}','NEEMA Toolkit <davidvt04@gmail.com>','Aprobado: Tu recurso Capacitación agrícola para comunidades rurales ha sido aprobado - NEEMA Toolkit','<!DOCTYPE html>\r\n<html lang=\"es\">\r\n<head>\r\n    <meta charset=\"UTF-8\">\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\r\n    <title>Recurso Aprobado - NEEMA Toolkit</title>\r\n</head>\r\n<body style=\"margin: 0; padding: 0; font-family: \'Open Sans\', Helvetica, Arial, sans-serif; background-color: #f4f4f4;\">\r\n    <div style=\"max-width: 560px; padding: 20px; background: #3D3073; border-radius: 10px; margin: 40px auto; font-size: 15px; color: #ffffff;\">\r\n        \r\n        <!-- Header -->\r\n        <div style=\"text-align: center; font-weight: bold; font-size: 28px; padding: 15px 0; border-bottom: 3px solid #5A45A0;\">\r\n            NEEMA Toolkit\r\n        </div>\r\n        \r\n        <!-- Body -->\r\n        <div style=\"padding: 30px; line-height: 1.6;\">\r\n            <h2 style=\"font-size: 22px; font-weight: 600; text-align: center; margin-bottom: 25px;\">\r\n                ¡Recurso Aprobado!\r\n            </h2>\r\n            \r\n            <p style=\"text-align: center; font-size: 16px; margin-bottom: 10px;\">\r\n                Hola <strong>gestorContenidos</strong>,\r\n            </p>\r\n            \r\n            <p style=\"text-align: center; font-size: 16px; margin-bottom: 30px;\">\r\n                ¡Tenemos buenas noticias! Tu recurso ha sido revisado y aprobado por el equipo de administración de NEEMA Toolkit.\r\n            </p>\r\n            \r\n            <!-- Cuadro destacado con información del recurso -->\r\n            <div style=\"background-color: rgba(246, 235, 248, 0.15); border-left: 4px solid #f6ebf8; border-radius: 4px; padding: 20px; margin: 25px 0;\">\r\n                <p style=\"margin: 0 0 10px 0; font-size: 14px; color: #e0dff4; text-transform: uppercase; letter-spacing: 0.5px;\">\r\n                    Recurso Publicado\r\n                </p>\r\n                <p style=\"margin: 0 0 15px 0; font-size: 20px; font-weight: bold; color: #ffffff;\">\r\n                    Capacitación agrícola para comunidades rurales                </p>\r\n                <p style=\"margin: 0; font-size: 14px; color: #e0dff4;\">\r\n                    <strong>Fecha de aprobación:</strong> 18/05/2026 17:25                </p>\r\n            </div>\r\n            \r\n            <p style=\"text-align: center; font-size: 16px; margin-bottom: 30px;\">\r\n                Tu recurso ya está disponible públicamente en el sitio web y los usuarios pueden acceder a él.\r\n            </p>\r\n            \r\n            <!-- Botón de acción -->\r\n            <div style=\"text-align: center; margin-bottom: 30px;\">\r\n                <a style=\"background-color: #f6ebf8; color: #3d3073; padding: 12px 30px; text-decoration: none; border-radius: 5px; font-weight: 600; display: inline-block;\" href=\"http://neema-toolkit-tfg.local/recursos/capacitacion-agricola-para-comunidades-rurales/\">\r\n                    Ver Recurso Publicado\r\n                </a>\r\n            </div>\r\n            \r\n            <p style=\"text-align: center; font-size: 16px; margin-top: 25px;\">\r\n                Gracias por tu contribución a NEEMA Toolkit.\r\n            </p>\r\n        </div>\r\n        \r\n        <!-- Footer -->\r\n        <div style=\"text-align: center; font-size: 13px; color: #d1cfe8; padding: 20px 30px;\">\r\n            Este es un mensaje automático de NEEMA Toolkit.<br />\r\n            Si tienes alguna pregunta, no dudes en contactar con el equipo de administración.\r\n        </div>\r\n        \r\n    </div>\r\n</body>\r\n</html>\r\n','a:4:{s:8:\"reply-to\";a:0:{}s:2:\"cc\";a:0:{}s:3:\"bcc\";a:0:{}s:12:\"content-type\";s:9:\"text/html\";}','a:0:{}','sent','a:1:{s:9:\"MessageId\";s:16:\"19e3bb1a15a7f442\";}','a:1:{s:8:\"provider\";s:5:\"gmail\";}',0,0,NULL,'2026-05-18 15:25:57',NULL);
