n                <li>Tweak: Use CSS Logical properties<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-1.0.0\",\"title\":\"1.0.0 - 2024-12-11\",\"description\":\"\\n            <ul>\\n                <li>Tweak: Minify starter-content images<\\/li>\\n                <li>Fix: Settings page styling<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-0.0.6\",\"title\":\"0.0.6 - 2024-12-04\",\"description\":\"\\n            <ul>\\n                <li>New: Add starter content<\\/li>\\n           <\\/ul>\"},{\"id\":\"hello-biz-0.0.5\",\"title\":\"0.0.5 - 2024-11-25\",\"description\":\"\\n            <ul>\\n                <li>Minor fixes<\\/li>\\n            <\\/ul>\"},{\"id\":\"hello-biz-0.0.4\",\"title\":\"0.0.4 - 2024-11-21\",\"description\":\"\\n            <ul>\\n                <li>Initial Public Release<\\/li>\\n            <\\/ul>\"}]\";}','off');
