INSERT INTO `wp_options` VALUES (5175,'wp_statistics_notifications','a:3:{s:4:\"data\";a:7:{i:0;a:11:{s:2:\"id\";i:23;s:5:\"title\";s:29:\"New Add-on: Marketing is Here\";s:4:\"icon\";s:14:\"\"\\ud83c\\udfaf\"\";s:11:\"description\";s:166:\"\"<p>Track campaigns, connect to Google Search Console, and set custom goals, now included in your Premium plan. Install the new Marketing add-on for free today.<\\/p>\"\";s:14:\"primary_button\";a:2:{s:5:\"title\";s:11:\"Install Now\";s:3:\"url\";s:50:\"{baseUrl}/wp-admin/admin.php?page=wps_plugins_page\";}s:16:\"secondary_button\";a:2:{s:5:\"title\";s:10:\"Learn More\";s:3:\"url\";s:159:\"https://wp-statistics.com/2025/07/introducing-the-marketing-add-on-gsc-campaigns-goals-more/?utm_source=wp-statistics&utm_medium=link&utm_campaign=notification\";}s:16:\"background_color\";s:7:\"inherit\";s:11:\"plugin_name\";s:13:\"WP Statistics\";s:12:\"activated_at\";s:16:\"2025-07-23T06:00\";s:10:\"expires_at\";N;s:4:\"tags\";a:1:{i:0;s:10:\"is-premium\";}}i:1;a:11:{s:2:\"id\";i:22;s:5:\"title\";s:32:\"Introducing the Marketing Add-on\";s:4:\"icon\";s:14:\"\"\\u2600\\ufe0f\"\";s:11:\"description\";s:108:\"\"Connect to Google Search Console, track custom events and goals, and get insights from your UTM campaigns.\"\";s:14:\"primary_button\";a:2:{s:5:\"title\";s:10:\"Learn More\";s:3:\"url\";s:159:\"https://wp-statistics.com/2025/07/introducing-the-marketing-add-on-gsc-campaigns-goals-more/?utm_source=wp-statistics&utm_medium=link&utm_campaign=notification\";}s:16:\"secondary_button\";a:2:{s:5:\"title\";s:16:\"View Add-on Page\";s:3:\"url\";s:125:\"https://wp-statistics.com/add-ons/wp-statistics-marketing/?utm_source=wp-statistics&utm_medium=link&utm_campaign=notification\";}s:16:\"background_color\";s:7:\"inherit\";s:11:\"plugin_name\";s:13:\"WP Statistics\";s:12:\"activated_at\";s:16:\"2025-07-23T05:51\";s:10:\"expires_at\";N;s:4:\"tags\";a:1:{i:0;s:10:\"no-premium\";}}i:2;a:11:{s:2:\"id\";i:21;s:5:\"title\";s:28:\"WP Statistics 14.15 is here!\";s:4:\"icon\";s:14:\"\"\\ud83d\\ude80\"\";s:11:\"description\";s:135:\"\"New Visitor, Page, and Device Overview reports, plus a fresh look for your reports and other improvements. Take a look at what\'s new.\"\";s:14:\"primary_button\";a:2:{s:5:\"title\";s:17:\"View What’s New\";s:3:\"url\";s:122:\"https://wp-statistics.com/release/wp-statistics-v14-15/?utm_source=wp-statistics&utm_medium=link&utm_campaign=notification\";}s:16:\"secondary_button\";a:2:{s:5:\"title\";s:17:\"Suggest a Feature\";s:3:\"url\";s:52:\"https://feedback.veronalabs.com/boards/wp-statistics\";}s:16:\"background_color\";s:7:\"inherit\";s:11:\"plugin_name\";s:13:\"WP Statistics\";s:12:\"activated_at\";s:16:\"2025-07-23T05:47\";s:10:\"expires_at\";N;s:4:\"tags\";a:0:{}}i:3;a:11:{s:2:\"id\";i:7;s:5:\"title\";s:23:\"Data Plus v2.6 is live!\";s:4:\"icon\";s:14:\"\"\\u2600\\ufe0f\"\";s:11:\"description\";s:168:\"\"<p>Upgrade now to get Entry &amp; Exit Page reports, the new Top Source Categories widget, and layout fixes\\u2014all designed to sharpen your insights instantly.<\\/p>\"\";s:14:\"primary_button\";a:2:{s:5:\"title\";s:16:\"Update Data Plus\";s:3:\"url\";s:34:\"{baseUrl}/wp-admin/update-core.php\";}s:16:\"secondary_button\";a:2:{s:5:\"title\";s:19:\"View full changelog\";s:3:\"url\";s:116:\"https://wp-statistics.com/release/data-plus-v2-6/?utm_source=wp-statistics&utm_medium=link&utm_campaign=notification\";}s:16:\"background_color\";s:7:\"inherit\";s:11:\"plugin_name\";s:13:\"WP Statistics\";s:12:\"activated_at\";s:16:\"2025-06-04T07:18\";s:10:\"expires_at\";N;s:4:\"tags\";a:1:{i:0;s:19:\"has-addon-data-plus\";}}i:4;a:11:{s:2:\"id\";i:5;s:5:\"title\";s:37:\"Tell Us Your Next Must‑Have Feature\";s:4:\"icon\";s:20:\"\"\\ud83d\\uddf3\\ufe0f\"\";s:11:\"description\";s:129:\"\"<p>We just opened a public board where you can post ideas and vote on others. Help shape the future of WP\\u202fStatistics.<\\/p>\"\";s:14:\"primary_button\";a:2:{s:5:\"title\";s:13:\"Share an idea\";s:3:\"url\";s:52