INSERT INTO `wp_postmeta` VALUES (291,106,'_edit_lock','1768730623:1');
INSERT INTO `wp_postmeta` VALUES (293,106,'_modulo_description_es','Este módulo aborda la interrelación entre el ODS 2 y otros ODS (4, 5, 13, 15). La combinación de enfoques teóricos y prácticos, apoyada en recursos tecnológicos, permite formar a los participantes para enfrentar desafíos reales y contribuir a soluciones sostenibles en la región del África Occidental y el Sahel.');
INSERT INTO `wp_postmeta` VALUES (294,106,'_modulo_objective_es','Capacitar a los estudiantes en los principios y la aplicación práctica de la resiliencia alimentaria y nutricional (RAN), mediante un enfoque integral de los ODS, con especial énfasis en el ODS 2 y su interrelación con otros ODS.');
INSERT INTO `wp_postmeta` VALUES (295,106,'_modulo_skills_es','Ser capaces de diseñar y evaluar políticas de RAN, analizar indicadores (disponibilidad, consumo, vulnerabilidad), desarrollar intervenciones basadas en los ODS, entre otros.');
INSERT INTO `wp_postmeta` VALUES (296,106,'_modulo_title_en','M4. SDG 2: Zero Hunger');
INSERT INTO `wp_postmeta` VALUES (297,106,'_modulo_description_en','This module addresses the interrelation between SDG 2 and other SDGs (4, 5, 13, 15). The combination of theoretical and practical approaches, supported by technological resources, enables participants to face real challenges and contribute to sustainable solutions in the West Africa and Sahel region.');
INSERT INTO `wp_postmeta` VALUES (298,106,'_modulo_objective_en','Train students in the principles and practical application of Food and Nutrition Resilience (FNR), through a comprehensive SDG-focused approach, with special emphasis on SDG 2 and its interrelation with other SDGs.');
INSERT INTO `wp_postmeta` VALUES (299,106,'_modulo_skills_en','Be capable of designing and evaluating FNR policies, analyzing indicators (availability, consumption, vulnerability), developing SDG-based interventions, among others.');
INSERT INTO `wp_postmeta` VALUES (300,106,'_modulo_title_fr','M4. ODD 2 : Faim zéro');
INSERT INTO `wp_postmeta` VALUES (301,106,'_modulo_description_fr','Ce module aborde l’interrelation entre l’ODD 2 et les autres ODD (4, 5, 13, 15). La combinaison d’approches théoriques et pratiques, soutenue par des ressources technologiques, permet aux participants de relever des défis réels et de contribuer à des solutions durables dans la région de l’Afrique de l’Ouest et du Sahel.');
INSERT INTO `wp_postmeta` VALUES (302,106,'_modulo_objective_fr','Former les étudiants aux principes et à l’application pratique de la résilience alimentaire et nutritionnelle (RAN), à travers une approche globale centrée sur les ODD, avec un accent particulier sur l’ODD 2 et son interrelation avec les autres ODD.');
INSERT INTO `wp_postmeta` VALUES (303,106,'_modulo_skills_fr','Être capables de concevoir et d’évaluer des politiques de RAN, analyser les indicateurs (disponibilité, consommation, vulnérabilité), développer des interventions basées sur les ODD, entre autres.');
