INSERT INTO `wp_postmeta` VALUES (3732,525,'_categoria_organismo_description','<strong data-start=\"177\" data-end=\"211\">Los organismos internacionales</strong> son entidades que operan a nivel supranacional y cuyo objetivo es coordinar, promover y apoyar acciones relacionadas con la ayuda alimentaria y la resiliencia alimentaria y nutricional en distintos países y regiones. Estas organizaciones suelen trabajar en colaboración con gobiernos, organizaciones no gubernamentales y otros actores para ofrecer apoyo técnico, orientación estratégica y marcos de actuación a escala regional o global.');
INSERT INTO `wp_postmeta` VALUES (3733,527,'_categoria_organismo_description','<p data-start=\"85\" data-end=\"560\"><strong data-start=\"85\" data-end=\"116\">International organizations</strong> are entities that operate at a supranational level and whose objective is to coordinate, promote, and support actions related to food aid and food and nutrition resilience across different countries and regions. These organizations typically work in collaboration with governments, non-governmental organizations, and other stakeholders to provide technical support, strategic guidance, and frameworks for action at a regional or global scale.</p>');
INSERT INTO `wp_postmeta` VALUES (3734,528,'_categoria_organismo_description','<strong data-start=\"584\" data-end=\"617\">Les organismes internationaux</strong> sont des entités qui opèrent à un niveau supranational et dont l’objectif est de coordonner, promouvoir et soutenir des actions liées à l’aide alimentaire et à la résilience alimentaire et nutritionnelle dans différents pays et régions. Ces organisations travaillent généralement en collaboration avec les gouvernements, les organisations non gouvernementales et d’autres acteurs afin de fournir un appui technique, une orientation stratégique et des cadres d’action à l’échelle régionale ou mondiale.');
