INSERT INTO `wp_postmeta` VALUES (4768,693,'_member_url','https://www.us.es/');
INSERT INTO `wp_postmeta` VALUES (4769,693,'_member_description_es','La Universidad de Sevilla es una de las instituciones académicas más antiguas y prestigiosas de España, fundada en el siglo XVI y ubicada en Sevilla.\r\nDestaca por su amplia oferta educativa, su investigación y su histórico edificio principal, la Real Fábrica de Tabacos.');
INSERT INTO `wp_postmeta` VALUES (4770,693,'_member_description_en','The Universidad de Sevilla is one of the oldest and most prestigious academic institutions in Spain, founded in the 16th century and located in Seville.\r\nIt stands out for its wide range of programs, its research, and its historic main building, the former Royal Tobacco Factory.');
INSERT INTO `wp_postmeta` VALUES (4771,693,'_member_description_fr','La Universidad de Sevilla est l’une des institutions académiques les plus anciennes et prestigieuses d’Espagne, fondée au XVIe siècle et située à Séville.\r\nElle se distingue par son large éventail de formations, sa recherche et son bâtiment historique principal, l’ancienne manufacture royale de tabac.');
INSERT INTO `wp_postmeta` VALUES (4772,693,'_member_order','1');
INSERT INTO `wp_postmeta` VALUES (4773,693,'_member_entities','a:1:{i:0;a:7:{s:5:\"title\";s:53:\"Escuela Técnica Superior de Ingeniería Informática\";s:3:\"url\";s:30:\"https://www.informatica.us.es/\";s:5:\"image\";s:74:\"http://neema-toolkit-tfg.local/wp-content/uploads/2026/02/ETSII-scaled.png\";s:14:\"description_es\";s:301:\"La Escuela Técnica Superior de Ingeniería Informática de la Universidad de Sevilla es un centro especializado en la formación en ingeniería informática y tecnologías de la información.\r\nDestaca por su enfoque práctico, su actividad investigadora y su colaboración con el sector tecnológico.\";s:14:\"description_en\";s:276:\"The Escuela Técnica Superior de Ingeniería Informática of the University of Seville is a center specialized in computer engineering and information technology education.\r\nIt stands out for its practical approach, research activity, and collaboration with the tech industry.\";s:14:\"description_fr\";s:310:\"L’Escuela Técnica Superior de Ingeniería Informática de l’Université de Séville est un centre spécialisé dans la formation en ingénierie informatique et technologies de l’information.\r\nElle se distingue par son orientation pratique, sa recherche et sa collaboration avec le secteur technologique.\";s:12:\"participants\";a:1:{i:0;a:6:{s:5:\"title\";s:22:\"David Valencia Toscano\";s:3:\"url\";s:49:\"https://www.linkedin.com/in/davidvalenciatoscano/\";s:5:\"image\";s:0:\"\";s:14:\"description_es\";s:21:\"Descripción David ES\";s:14:\"description_en\";s:21:\"Descripción David EN\";s:14:\"description_fr\";s:21:\"Descripción David FR\";}}}}');
