INSERT INTO `wp_postmeta` VALUES (4874,702,'descripcion_es','Este recurso aborda estrategias para fortalecer las cadenas de valor agrícolas mediante la mejora del acceso a mercados, la capacitación técnica y el uso de prácticas sostenibles. Se centra en apoyar a pequeños productores agrícolas para incrementar sus ingresos, reducir pérdidas poscosecha y fomentar la seguridad alimentaria en comunidades rurales.');
INSERT INTO `wp_postmeta` VALUES (4875,702,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (4876,702,'descripcion_en','This resource explores strategies to strengthen agricultural value chains through improved market access, technical training, and the adoption of sustainable practices. It focuses on supporting smallholder farmers to increase income, reduce post-harvest losses, and promote food security in rural communities.');
INSERT INTO `wp_postmeta` VALUES (4877,702,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (4878,702,'descripcion_fr','Cette ressource présente des stratégies visant à renforcer les chaînes de valeur agricoles grâce à un meilleur accès aux marchés, à la formation technique et à l’adoption de pratiques durables. Elle met l’accent sur le soutien aux petits producteurs agricoles afin d’augmenter leurs revenus, de réduire les pertes après récolte et de promouvoir la sécurité alimentaire dans les communautés rurales.');
INSERT INTO `wp_postmeta` VALUES (4879,702,'_descripcion_fr','field_6933091d8acd0');
