INSERT INTO `wp_postmeta` VALUES (4904,704,'descripcion_es','Este recurso presenta herramientas digitales orientadas a mejorar la intervención comunitaria y la participación ciudadana en proyectos de desarrollo social. Incluye metodologías colaborativas, plataformas de comunicación y recursos tecnológicos que facilitan la coordinación, el seguimiento de actividades y la inclusión de comunidades vulnerables.');
INSERT INTO `wp_postmeta` VALUES (4905,704,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (4906,704,'descripcion_en','This resource presents digital tools aimed at improving community intervention and citizen participation in social development projects. It includes collaborative methodologies, communication platforms, and technological resources that facilitate coordination, activity monitoring, and the inclusion of vulnerable communities.');
INSERT INTO `wp_postmeta` VALUES (4907,704,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (4908,704,'descripcion_fr','Cette ressource présente des outils numériques destinés à améliorer l’intervention communautaire et la participation citoyenne dans les projets de développement social. Elle comprend des méthodologies collaboratives, des plateformes de communication et des ressources technologiques facilitant la coordination, le suivi des activités et l’inclusion des communautés vulnérables.');
