INSERT INTO `wp_postmeta` VALUES (4934,706,'descripcion_es','Este recurso recopila buenas prácticas y enfoques pedagógicos para promover la educación intercultural en distintos contextos educativos. Incluye estrategias para fomentar la inclusión, el respeto por la diversidad cultural y la participación activa de estudiantes y comunidades en procesos de aprendizaje colaborativo.');
INSERT INTO `wp_postmeta` VALUES (4935,706,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (4936,706,'descripcion_en','This resource compiles best practices and pedagogical approaches to promote intercultural education in different educational contexts. It includes strategies to foster inclusion, respect for cultural diversity, and the active participation of students and communities in collaborative learning processes.');
INSERT INTO `wp_postmeta` VALUES (4937,706,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (4938,706,'descripcion_fr','Cette ressource rassemble des bonnes pratiques et des approches pédagogiques visant à promouvoir l’éducation interculturelle dans différents contextes éducatifs. Elle inclut des stratégies pour favoriser l’inclusion, le respect de la diversité culturelle et la participation active des étudiants et des communautés dans des processus d’apprentissage collaboratif.');
