INSERT INTO `wp_postmeta` VALUES (4995,710,'descripcion_es','Este recurso explora iniciativas de innovación social aplicadas al desarrollo rural y la mejora de la calidad de vida en comunidades locales. Presenta experiencias colaborativas, modelos participativos y herramientas digitales para impulsar el emprendimiento y la cohesión social.');
INSERT INTO `wp_postmeta` VALUES (4996,710,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (4997,710,'descripcion_en','This resource explores social innovation initiatives applied to rural development and the improvement of quality of life in local communities. It presents collaborative experiences, participatory models, and digital tools to promote entrepreneurship and social cohesion.');
INSERT INTO `wp_postmeta` VALUES (4998,710,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (4999,710,'descripcion_fr','Cette ressource explore des initiatives d’innovation sociale appliquées au développement rural et à l’amélioration de la qualité de vie dans les communautés locales. Elle présente des expériences collaboratives, des modèles participatifs et des outils numériques favorisant l’entrepreneuriat et la cohésion sociale.');
