INSERT INTO `wp_postmeta` VALUES (5025,712,'descripcion_es','Este recurso aborda estrategias para mejorar la seguridad alimentaria y promover hábitos de nutrición saludable en comunidades vulnerables. Incluye programas de sensibilización, iniciativas de producción local y acciones para prevenir la malnutrición.');
INSERT INTO `wp_postmeta` VALUES (5026,712,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5027,712,'descripcion_en','This resource addresses strategies to improve food security and promote healthy nutrition habits in vulnerable communities. It includes awareness programs, local production initiatives, and actions to prevent malnutrition.');
