INSERT INTO `wp_postmeta` VALUES (5055,714,'descripcion_es','Este recurso destaca la importancia de la participación juvenil en proyectos de cooperación internacional y desarrollo comunitario. Incluye metodologías participativas, actividades formativas y herramientas para fortalecer el liderazgo y la implicación social de los jóvenes.');
INSERT INTO `wp_postmeta` VALUES (5056,714,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5057,714,'descripcion_en','This resource highlights the importance of youth participation in international cooperation and community development projects. It includes participatory methodologies, training activities, and tools to strengthen youth leadership and social engagement.');
INSERT INTO `wp_postmeta` VALUES (5058,714,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (5059,714,'descripcion_fr','Cette ressource met en évidence l’importance de la participation des jeunes dans les projets de coopération internationale et de développement communautaire. Elle comprend des méthodologies participatives, des activités de formation et des outils pour renforcer le leadership et l’engagement social des jeunes.');
