INSERT INTO `wp_postmeta` VALUES (5085,717,'descripcion_es','Este recurso ofrece herramientas y estrategias para la gestión sostenible del agua en contextos rurales y urbanos. Analiza prácticas de ahorro, reutilización y acceso equitativo a los recursos hídricos para contribuir al desarrollo sostenible.');
INSERT INTO `wp_postmeta` VALUES (5086,717,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5087,717,'descripcion_en','This resource provides tools and strategies for sustainable water management in rural and urban contexts. It analyzes water-saving practices, reuse initiatives, and equitable access to water resources to support sustainable development.');
INSERT INTO `wp_postmeta` VALUES (5088,717,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (5089,717,'descripcion_fr','<p data-start=\"5430\" data-end=\"5721\">Cette ressource propose des outils et des stratégies pour la gestion durable de l’eau dans des contextes ruraux et urbains. Elle analyse des pratiques d’économie d’eau, de réutilisation et d’accès équitable aux ressources hydriques afin de contribuer au développement durable.</p>');
