INSERT INTO `wp_postmeta` VALUES (5115,719,'descripcion_es','Este recurso presenta tecnologías abiertas y recursos digitales diseñados para mejorar el acceso a la educación en entornos rurales. Incluye plataformas educativas, contenidos colaborativos y soluciones tecnológicas adaptadas a contextos con conectividad limitada.');
INSERT INTO `wp_postmeta` VALUES (5116,719,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5117,719,'descripcion_en','This resource presents open technologies and digital resources designed to improve access to education in rural environments. It includes educational platforms, collaborative content, and technological solutions adapted to areas with limited connectivity.');
INSERT INTO `wp_postmeta` VALUES (5118,719,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (5119,719,'descripcion_fr','Cette ressource présente des technologies ouvertes et des ressources numériques conçues pour améliorer l’accès à l’éducation dans les zones rurales. Elle comprend des plateformes éducatives, des contenus collaboratifs et des solutions technologiques adaptées aux contextes à connectivité limitée.');
