INSERT INTO `wp_postmeta` VALUES (5145,721,'descripcion_es','Este recurso analiza iniciativas orientadas al empoderamiento de las mujeres en el sector agrícola mediante formación, acceso a recursos y fortalecimiento del liderazgo comunitario. Se enfoca en promover la igualdad de oportunidades y el desarrollo sostenible en comunidades rurales.');
INSERT INTO `wp_postmeta` VALUES (5146,721,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5147,721,'descripcion_en','This resource examines initiatives aimed at empowering women in the agricultural sector through training, access to resources, and strengthened community leadership. It focuses on promoting equal opportunities and sustainable development in rural communities.');
INSERT INTO `wp_postmeta` VALUES (5148,721,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (5149,721,'descripcion_fr','Cette ressource analyse des initiatives visant à renforcer l’autonomisation des femmes dans le secteur agricole grâce à la formation, à l’accès aux ressources et au développement du leadership communautaire. Elle met l’accent sur la promotion de l’égalité des chances et du développement durable dans les communautés rurales.');
