INSERT INTO `wp_postmeta` VALUES (5760,766,'descripcion_es','Este recurso ofrece programas y materiales de capacitación agrícola orientados al fortalecimiento de capacidades en comunidades rurales. Incluye técnicas de cultivo sostenible, gestión de recursos naturales y estrategias para mejorar la productividad agrícola y la seguridad alimentaria.');
INSERT INTO `wp_postmeta` VALUES (5761,766,'_descripcion_es','field_69039874e99c7');
INSERT INTO `wp_postmeta` VALUES (5762,766,'descripcion_en','This resource provides agricultural training programs and materials aimed at strengthening capacities in rural communities. It includes sustainable farming techniques, natural resource management, and strategies to improve agricultural productivity and food security.');
INSERT INTO `wp_postmeta` VALUES (5763,766,'_descripcion_en','field_693308f88accf');
INSERT INTO `wp_postmeta` VALUES (5764,766,'descripcion_fr','Cette ressource propose des programmes et des supports de formation agricole destinés au renforcement des capacités des communautés rurales. Elle comprend des techniques de culture durable, la gestion des ressources naturelles et des stratégies visant à améliorer la productivité agricole et la sécurité alimentaire.');
INSERT INTO `wp_postmeta` VALUES (5765,766,'_descripcion_fr','field_6933091d8acd0');
