INSERT INTO `wp_termmeta` VALUES (1,3,'_pll_strings_translations','a:130:{i:0;a:2:{i:0;s:13:\"NEEMA-Toolkit\";i:1;s:13:\"NEEMA-Toolkit\";}i:1;a:2:{i:0;s:15:\"j \\d\\e F \\d\\e Y\";i:1;s:15:\"j \\d\\e F \\d\\e Y\";}i:2;a:2:{i:0;s:3:\"H:i\";i:1;s:3:\"H:i\";}i:3;a:2:{i:0;s:9:\"Volver a \";i:1;s:8:\"Volver a\";}i:4;a:2:{i:0;s:37:\"Resiliencia Alimentaria y Nutricional\";i:1;s:37:\"Resiliencia Alimentaria y Nutricional\";}i:5;a:2:{i:0;s:15:\"Iniciar Sesión\";i:1;s:15:\"Iniciar Sesión\";}i:6;a:2:{i:0;s:19:\"Guía Introductoria\";i:1;s:19:\"Guía Introductoria\";}i:7;a:2:{i:0;s:16:\"Programas de RAN\";i:1;s:16:\"Programas de RAN\";}i:8;a:2:{i:0;s:31:\"Ayuda Alimentaria y Resiliencia\";i:1;s:31:\"Ayuda Alimentaria y Resiliencia\";}i:9;a:2:{i:0;s:18:\"Servicios de apoyo\";i:1;s:18:\"Servicios de apoyo\";}i:10;a:2:{i:0;s:43:\"¡Bienvenido<br> a la Toolkit de<br> NEEMA!\";i:1;s:43:\"¡Bienvenido<br> a la Toolkit de<br> NEEMA!\";}i:11;a:2:{i:0;s:31:\"Qué es la caja de herramientas\";i:1;s:31:\"Qué es la caja de herramientas\";}i:12;a:2:{i:0;s:379:\"<b>La Caja de Herramientas</b> o <b>Toolkit</b> es un gestor de contenidos diseñado para consultar y crear formaciones, proyectos, informes, normativas y otros recursos de Seguridad Alimentaria. Reúne documentos, bases de datos, estadísticas, casos prácticos y más, organizados de forma intuitiva para facilitar el trabajo de los usuarios y aportar eficiencia e innovación.\";i:1;s:379:\"<b>La Caja de Herramientas</b> o <b>Toolkit</b> es un gestor de contenidos diseñado para consultar y crear formaciones, proyectos, informes, normativas y otros recursos de Seguridad Alimentaria. Reúne documentos, bases de datos, estadísticas, casos prácticos y más, organizados de forma intuitiva para facilitar el trabajo de los usuarios y aportar eficiencia e innovación.\";}i:13;a:2:{i:0;s:311:\"La <b>Toolkit</b>, parte del Proyecto NEEMA de la Universidad de Sevilla financiado por ERASMUS+, busca adaptar el Pacto Verde Europeo y la Estrategia “De la Granja a la Mesa” al Sahel y África Occidental, promoviendo resiliencia alimentaria y nutricional frente a sequías, conflictos y cambio climático.\";i:1;s:311:\"La <b>Toolkit</b>, parte del Proyecto NEEMA de la Universidad de Sevilla financiado por ERASMUS+, busca adaptar el Pacto Verde Europeo y la Estrategia “De la Granja a la Mesa” al Sahel y África Occidental, promoviendo resiliencia alimentaria y nutricional frente a sequías, conflictos y cambio climático.\";}i:14;a:2:{i:0;s:14:\"Quiénes somos\";i:1;s:14:\"Quiénes somos\";}i:15;a:2:{i:0;s:34:\"Parece que esta página no existe.\";i:1;s:34:\"Parece que esta página no existe.\";}i:16;a:2:{i:0;s:69:\"Es posible que el enlace no exista o que la página haya sido movida.\";i:1;s:69:\"Es posible que el enlace no exista o que la página haya sido movida.\";}i:17;a:2:{i:0;s:16:\"Volver al inicio\";i:1;s:16:\"Volver al inicio\";}i:18;a:2:{i:0;s:65:\"Resumen de los programas de Resiliencia Alimentaria y Nutricional\";i:1;s:65:\"Resumen de los programas de Resiliencia Alimentaria y Nutricional\";}i:19;a:2:{i:0;s:73:\"Como parte del Proyecto NEEMA, liderado por la Universidad de Sevilla ...\";i:1;s:206:\"Como parte del Proyecto NEEMA, liderado por la Universidad de Sevilla y financiado por ERASMUS+, se ha diseñado un plan de estudios compuesto por siete módulos sobre Resiliencia Alimentaria y Nutricional.\";}i:20;a:2:{i:0;s:8:\"Buscador\";i:1;s:8:\"Buscador\";}i:21;a:2:{i:0;s:8:\"Módulos\";i:1;s:8:\"Módulos\";}i:22;a:2:{i:0;s:8:\"Objetivo\";i:1;s:8:\"Objetivo\";}i:23;a:2:{i:0;s:23:\"Competencias a adquirir\";i:1;s:23:\"Competencias a adquirir\";}i:24;a:2:{i:0;s:8:\"Recursos\";i:1;s:8:\"Recursos\";}i:25;a:2:{i:0;s:12:\"Contextuales\";i:1;s:12:\"Contextuales\";}i:26;a:2:{i:0;s:10:\"Formativos\";i:1;s:10:\"Formativos\";}i:27;a:2:{i:0;s:14:\"Metodológicos\";i:1;s:14:\"Metodológicos\";}i:28;a:2:{i:0;s:15:\"Procedimentales\";i:1;s:15:\"Procedimentales\";}i:29;a:2:{i:0;s:31:\"Buscar por palabras o frases...\";i:1;s:31:\"Buscar por palabra