INSERT INTO `wp_termmeta` VALUES (2,6,'_pll_strings_translations','a:199:{i:0;a:2:{i:0;s:13:\"NEEMA-Toolkit\";i:1;s:13:\"NEEMA-Toolkit\";}i:1;a:2:{i:0;s:15:\"j \\d\\e F \\d\\e Y\";i:1;s:15:\"j \\d\\e F \\d\\e Y\";}i:2;a:2:{i:0;s:3:\"H:i\";i:1;s:3:\"H:i\";}i:3;a:2:{i:0;s:9:\"Volver a \";i:1;s:9:\"Retour à\";}i:4;a:2:{i:0;s:37:\"Resiliencia Alimentaria y Nutricional\";i:1;s:41:\"Résilience Alimentaire et Nutritionnelle\";}i:5;a:2:{i:0;s:15:\"Iniciar Sesión\";i:1;s:12:\"Se connecter\";}i:6;a:2:{i:0;s:19:\"Guía Introductoria\";i:1;s:17:\"Guide Introductif\";}i:7;a:2:{i:0;s:16:\"Programas de RAN\";i:1;s:14:\"Programmes RAN\";}i:8;a:2:{i:0;s:31:\"Ayuda Alimentaria y Resiliencia\";i:1;s:37:\"Assistance Alimentaire et Résilience\";}i:9;a:2:{i:0;s:18:\"Servicios de apoyo\";i:1;s:19:\"Services de soutien\";}i:10;a:2:{i:0;s:43:\"¡Bienvenido<br> a la Toolkit de<br> NEEMA!\";i:1;s:53:\"Bienvenue<br> dans la boîte à outils<br> de NEEMA !\";}i:11;a:2:{i:0;s:31:\"Qué es la caja de herramientas\";i:1;s:37:\"Qu’est-ce que la boîte à outils ?\";}i:12;a:2:{i:0;s:379:\"<b>La Caja de Herramientas</b> o <b>Toolkit</b> es un gestor de contenidos diseñado para consultar y crear formaciones, proyectos, informes, normativas y otros recursos de Seguridad Alimentaria. Reúne documentos, bases de datos, estadísticas, casos prácticos y más, organizados de forma intuitiva para facilitar el trabajo de los usuarios y aportar eficiencia e innovación.\";i:1;s:422:\"<b>La Boîte à Outils</b> ou <b>Toolkit</b> est un gestionnaire de contenus conçu pour consulter et créer des formations, projets, rapports, réglementations et autres ressources en Sécurité Alimentaire. Elle rassemble des documents, bases de données, statistiques, études de cas et bien plus encore, organisés de manière intuitive pour faciliter le travail des utilisateurs et apporter efficacité et innovation.\";}i:13;a:2:{i:0;s:311:\"La <b>Toolkit</b>, parte del Proyecto NEEMA de la Universidad de Sevilla financiado por ERASMUS+, busca adaptar el Pacto Verde Europeo y la Estrategia “De la Granja a la Mesa” al Sahel y África Occidental, promoviendo resiliencia alimentaria y nutricional frente a sequías, conflictos y cambio climático.\";i:1;s:354:\"Le <b>Toolkit</b>, faisant partie du projet NEEMA de l’Université de Séville et financé par ERASMUS+, vise à adapter le Pacte Vert Européen et la stratégie « De la Ferme à la Table » au Sahel et en Afrique de l’Ouest, en promouvant la résilience alimentaire et nutritionnelle face aux sécheresses, aux conflits et au changement climatique.\";}i:14;a:2:{i:0;s:14:\"Quiénes somos\";i:1;s:15:\"Qui sommes-nous\";}i:15;a:2:{i:0;s:34:\"Parece que esta página no existe.\";i:1;s:40:\"Il semble que cette page n’existe pas.\";}i:16;a:2:{i:0;s:69:\"Es posible que el enlace no exista o que la página haya sido movida.\";i:1;s:79:\"Il est possible que le lien n’existe pas ou que la page ait été déplacée.\";}i:17;a:2:{i:0;s:16:\"Volver al inicio\";i:1;s:21:\"Retour à l’accueil\";}i:18;a:2:{i:0;s:65:\"Resumen de los programas de Resiliencia Alimentaria y Nutricional\";i:1;s:68:\"Résumé des programmes de résilience alimentaire et nutritionnelle\";}i:19;a:2:{i:0;s:73:\"Como parte del Proyecto NEEMA, liderado por la Universidad de Sevilla ...\";i:1;s:211:\"Dans le cadre du projet NEEMA, dirigé par l’Université de Séville et financé par ERASMUS+, un programme d’études composé de sept modules sur la Résilience Alimentaire et Nutritionnelle a été conçu.\";}i:20;a:2:{i:0;s:8:\"Buscador\";i:1;s:9:\"Recherche\";}i:21;a:2:{i:0;s:8:\"Módulos\";i:1;s:7:\"Modules\";}i:22;a:2:{i:0;s:8:\"Objetivo\";i:1;s:8:\"Objectif\";}i:23;a:2:{i:0;s:23:\"Competencias a adquirir\";i:1;s:25:\"Compétences à acquérir\";}i:24;a:2:{i:0;s:8:\"Recursos\";i:1;s:10:\"Ressources\";}i:25;a:2:{i:0;s:12:\"Contextuales\";i:1;s:11:\"Contextuels\";}i:26;a:2:{i:0;s:10:\"Formativos\";i:1;s:9:\"Formatifs\";}i:27;a:2:{i:0;s:14:\"Metodológicos\";i:1;s:16:\"Méthodologiques\";}i:28;a:2:{i:0;s:15:\"Procedimentales\";i:1;s:12:\"Procéd